// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Search no data', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Search no data', async function() {
    await driver.get("http://localhost:4200/home");
    await driver.manage().window().setRect({ width: 1900, height: 1020 });
    await driver.findElement(By.css(".ant-row:nth-child(3) .ant-typography")).click();
    await driver.findElement(By.xpath("//li[contains(.,\'公開専門スキル一覧\')]")).click();
    await driver.findElement(By.css(".ant-select-selection-item")).click();
    await driver.findElement(By.css("#\\31 5 > .ant-select-item-option-content")).click();
    await driver.findElement(By.name("Search")).click();
    await driver.findElement(By.css(".ant-table-placeholder > .ant-table-cell")).click();
    assert(await driver.findElement(By.xpath("//td[contains(.,\'該当データがありません\')]")).getText() == "該当データがありません");
  });
});
